import React, { useState } from 'react';

const icons = [
  { key: 'health', label: 'Здоровье', src: '/icons/health.svg' },
  { key: 'money', label: 'Деньги', src: '/icons/money.svg' },
  { key: 'mood', label: 'Настроение', src: '/icons/mood.svg' },
  { key: 'income', label: 'Доход', src: '/icons/income.svg' },
];

function CharacterCreationModal({ visible, onClose, onCreate, loading, error }) {
  const [name, setName] = useState('Новый герой');
  const [role, setRole] = useState('Страховой агент');
  const [difficulty, setDifficulty] = useState('EASY');
  const [icon, setIcon] = useState('health');

  const handleSubmit = (event) => {
    event.preventDefault();
    onCreate({ fullName: `${name} — ${role}`, difficulty, icon });
  };

  if (!visible) {
    return null;
  }

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-panel" onClick={(event) => event.stopPropagation()}>
        <div className="modal-header">
          <h3>Создать персонажа</h3>
          <button type="button" className="modal-close" onClick={onClose}>
            ×
          </button>
        </div>
        <p className="modal-description">
          Заполни имя, выбери роль и сложность, чтобы начать новую игровую сессию.
        </p>
        {error && <div className="auth-error">{error}</div>}
        <form className="modal-form" onSubmit={handleSubmit}>
          <label className="modal-field">
            <span>Имя персонажа</span>
            <input
              value={name}
              onChange={(event) => setName(event.target.value)}
              placeholder="Например, ВладиК"
              required
              disabled={loading}
            />
          </label>
          <label className="modal-field">
            <span>Роль</span>
            <input
              value={role}
              onChange={(event) => setRole(event.target.value)}
              placeholder="Например, Страховой агент"
              required
              disabled={loading}
            />
          </label>
          <div className="modal-field modal-field--inline">
            <div>
              <span>Сложность</span>
              <select value={difficulty} onChange={(event) => setDifficulty(event.target.value)} disabled={loading}>
                <option value="EASY">Лёгкая</option>
                <option value="MEDIUM">Средняя</option>
                <option value="HARD">Сложная</option>
              </select>
            </div>
            <div>
              <span>Иконка</span>
              <div className="icon-picker">
                {icons.map((item) => (
                  <button
                    key={item.key}
                    type="button"
                    className={`icon-choice ${icon === item.key ? 'icon-choice--active' : ''}`}
                    onClick={() => setIcon(item.key)}
                    disabled={loading}
                  >
                    <img src={item.src} alt={item.label} />
                  </button>
                ))}
              </div>
            </div>
          </div>
          <div className="modal-actions">
            <button className="button button--secondary" type="button" onClick={onClose} disabled={loading}>
              Отмена
            </button>
            <button className="button button--primary" type="submit" disabled={loading}>
              {loading ? 'Создание...' : 'Создать персонажа'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default CharacterCreationModal;
